#include <cuda_runtime.h>

// Inline timer definitions from timer.h
#include <unistd.h>
#include <stdint.h>

__inline__ uint64_t rdtsc() 
{
    uint32_t lo, hi;
    // Use alternative for CUDA compatibility if rdtsc not available on GPU, 
    // but since timing is done on host for the whole region, we keep host rdtsc
    // Note: Inline asm for rdtsc is x86 specific. 
    // For portability in this translation, we assume x86 host as per original.
    __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
    return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

#define MIN(a, b) ((a)<=(b) ? (a) : (b))

// CUDA Kernel for the pathfinder step
__global__ void pathfinder_step(int* dst, int* src, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n >= cols) return;

    int min = src[n];
    if (n > 0) {
        int left = src[n-1];
        if (left < min) min = left;
    }
    if (n < cols-1) {
        int right = src[n+1];
        if (right < min) min = right;
    }
    dst[n] = wall_row[n] + min;
}

void check_cuda(cudaError_t result) {
    if (result != cudaSuccess) {
        fprintf(stderr, "CUDA Runtime Error: %s\n", cudaGetErrorString(result));
        exit(1);
    }
}

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void init(int argc, char** argv)
{
    if(argc==3){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    }else{
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; n<rows; n++)
        wall[n]=data+cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

int main(int argc, char** argv)
{
    run(argc,argv);
    return EXIT_SUCCESS;
}

